#include <stdio.h>

int* nextLargerElement(int* arr, int n) {
    static int ans[100000];
    for (int i = 0; i < n; i++) {
        ans[i] = -1;
        for (int j = i + 1; j < n; j++) {
            if (arr[j] > arr[i]) {
                ans[i] = arr[j];
                break;
            }
        }
    }
    return ans;
}

int main() {
    int n = 4;
    int arr[] = {1, 3, 2, 4};
    int* ans = nextLargerElement(arr, n);
    for (int i = 0; i < n; i++) {
        printf("%d ", ans[i]);
    }
    return 0;
}

