import java.util.*;

class Solution {
    public int[] nextLargerElement(int[] arr) {
        int n = arr.length;
        int[] ans = new int[n];
        Arrays.fill(ans, -1);
        for (int i = 0; i < n; i++) {
            for (int j = i + 1; j < n; j++) {
                if (arr[j] > arr[i]) {
                    ans[i] = arr[j];
                    break;
                }
            }
        }
        return ans;
    }
}

public class Main {
    public static void main(String[] args) {
        int n = 4;
        int[] arr = {1, 3, 2, 4};
        Solution sol = new Solution();
        int[] ans = sol.nextLargerElement(arr);
        for (int i = 0; i < n; i++) {
            System.out.print(ans[i] + " ");
        }
    }
}

