class Solution:
    def nextLargerElement(self, arr):
        n = len(arr)
        ans = [-1] * n
        for i in range(n):
            for j in range(i + 1, n):
                if arr[j] > arr[i]:
                    ans[i] = arr[j]
                    break
        return ans

